#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    for (int i = n - 1; i >= 0; i--) {
        printf("%d\n", arr[i]);
    }

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char str1[101], str2[101];
    scanf("%100s", str1);
    scanf("%100s", str2);

    int len1 = strlen(str1);
    int len2 = strlen(str2);

    char *result = (char *)malloc((len1 + len2 + 1) * sizeof(char));
    if (result == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    char *ptr = result;
    for (int i = 0; i < len1; i++) {
        *ptr = str1[i];
        ptr++;
    }
    for (int i = 0; i < len2; i++) {
        *ptr = str2[i];
        ptr++;
    }
    *ptr = '\0';

    printf("%s\n", result);

    free(result);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    double *arr = (double *)malloc(n * sizeof(double));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    double *ptr = arr;
    for (int i = 0; i < n; i++) {
        scanf("%lf", ptr);
        ptr++;
    }

    double sum = 0.0;
    ptr = arr;
    for (int i = 0; i < n; i++) {
        sum += *ptr;
        ptr++;
    }

    double average = sum / n;

    printf("%.2f\n", sum);
    printf("%.2f\n", average);

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int rows, cols;
    scanf("%d %d", &rows, &cols);

    int **matrix = (int **)malloc(rows * sizeof(int *));
    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }
    for (int i = 0; i < rows; i++) {
        matrix[i] = (int *)malloc(cols * sizeof(int));
        if (matrix[i] == NULL) {
            fprintf(stderr, "Memory allocation failed\n");
            return 1;
        }
    }

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }

    for (int j = 0; j < cols; j++) {
        for (int i = 0; i < rows; i++) {
            if (i > 0) printf(" ");
            printf("%d", matrix[i][j]);
        }
        printf("\n");
    }

    for (int i = 0; i < rows; i++) {
        free(matrix[i]);
    }
    free(matrix);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    int *result = (int *)malloc(n * sizeof(int));
    if (result == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    int result_count = 0;
    for (int i = 0; i < n; i++) {
        int is_duplicate = 0;
        for (int j = 0; j < result_count; j++) {
            if (arr[i] == result[j]) {
                is_duplicate = 1;
                break;
            }
        }
        if (!is_duplicate) {
            result[result_count] = arr[i];
            result_count++;
        }
    }

    for (int i = 0; i < result_count; i++) {
        printf("%d\n", result[i]);
    }

    free(arr);
    free(result);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    int n;
    scanf("%d", &n);

    char **strings = (char **)malloc(n * sizeof(char *));
    if (strings == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        char buffer[101];
        scanf("%100s", buffer);
        strings[i] = (char *)malloc((strlen(buffer) + 1) * sizeof(char));
        if (strings[i] == NULL) {
            fprintf(stderr, "Memory allocation failed\n");
            return 1;
        }
        strcpy(strings[i], buffer);
    }

    int max_len = strlen(strings[0]);
    char *longest = strings[0];

    for (int i = 1; i < n; i++) {
        int len = strlen(strings[i]);
        if (len > max_len) {
            max_len = len;
            longest = strings[i];
        }
    }

    printf("%d\n", max_len);
    printf("%s\n", longest);

    for (int i = 0; i < n; i++) {
        free(strings[i]);
    }
    free(strings);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    int *unique_vals = (int *)malloc(n * sizeof(int));
    int *frequencies = (int *)malloc(n * sizeof(int));
    if (unique_vals == NULL || frequencies == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    int unique_count = 0;

    int *ptr = arr;
    for (int i = 0; i < n; i++) {
        int val = *ptr;
        ptr++;

        int found = 0;
        for (int j = 0; j < unique_count; j++) {
            if (unique_vals[j] == val) {
                frequencies[j]++;
                found = 1;
                break;
            }
        }

        if (!found) {
            unique_vals[unique_count] = val;
            frequencies[unique_count] = 1;
            unique_count++;
        }
    }

    for (int i = 0; i < unique_count; i++) {
        printf("%d %d\n", unique_vals[i], frequencies[i]);
    }

    free(arr);
    free(unique_vals);
    free(frequencies);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int capacity = 10;
    int count = 0;
    int *arr = (int *)malloc(capacity * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    int val;
    while (scanf("%d", &val) == 1) {
        if (count == capacity) {
            capacity *= 2;
            int *new_arr = (int *)realloc(arr, capacity * sizeof(int));
            if (new_arr == NULL) {
                fprintf(stderr, "Memory allocation failed\n");
                return 1;
            }
            arr = new_arr;
        }
        arr[count] = val;
        count++;
    }

    int filter_count = 0;
    for (int i = 0; i < count; i++) {
        if (arr[i] >= 0) {
            filter_count++;
        }
    }

    int *filtered = (int *)malloc(filter_count * sizeof(int));
    if (filtered == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    int idx = 0;
    for (int i = 0; i < count; i++) {
        if (arr[i] >= 0) {
            filtered[idx] = arr[i];
            idx++;
        }
    }

    for (int i = 0; i < filter_count; i++) {
        printf("%d\n", filtered[i]);
    }

    free(arr);
    free(filtered);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - 1 - i; j++) {
            int *ptr1 = &arr[j];
            int *ptr2 = &arr[j + 1];

            if (*ptr1 > *ptr2) {
                int temp = *ptr1;
                *ptr1 = *ptr2;
                *ptr2 = temp;
            }
        }
    }

    for (int i = 0; i < n; i++) {
        printf("%d\n", arr[i]);
    }

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char buffer[101];
    scanf("%100s", buffer);

    int len = strlen(buffer);
    char *str = (char *)malloc((len + 1) * sizeof(char));
    if (str == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }
    strcpy(str, buffer);

    char *left = str;
    char *right = str + len - 1;

    while (left < right) {
        char temp = *left;
        *left = *right;
        *right = temp;

        left++;
        right--;
    }

    printf("%s\n", str);

    free(str);
    return 0;
}
